+/// bd-db300.6.1.1: Record a statement execution for reuse-distance tracking.
+///
+/// Tracks how often statements repeat and the distance (in statements) between
+/// repeats. Also tracks whether reuse is lane-local (same thread) or cross-lane.
+#[inline]
+fn record_statement_execution(fingerprint_hash: u64) {
+    if !hot_path_profile_enabled() {
+        return;
+    }
+
+    // Get current global sequence and increment atomically.
+    let current_seq = FSQLITE_STATEMENT_GLOBAL_SEQ.fetch_add(1, AtomicOrdering::Relaxed);
+    let current_thread_id = std::thread::current().id().as_u64().into();
+
+    FSQLITE_STATEMENT_LAST_EXEC.with(|history| {
+        let mut history = history.borrow_mut();
+        if let Some(&(last_seq, last_thread_id)) = history.get(&fingerprint_hash) {
+            // This is a reuse event.
+            let distance = current_seq.saturating_sub(last_seq);
+            FSQLITE_STATEMENT_REUSE_COUNT.fetch_add(1, AtomicOrdering::Relaxed);
+            FSQLITE_STATEMENT_REUSE_DISTANCE_SUM.fetch_add(distance, AtomicOrdering::Relaxed);
+
+            // Update max distance if this is larger.
+            let mut current_max = FSQLITE_STATEMENT_MAX_REUSE_DISTANCE.load(AtomicOrdering::Relaxed);
+            while distance > current_max {
+                match FSQLITE_STATEMENT_MAX_REUSE_DISTANCE.compare_exchange_weak(
+                    current_max,
+                    distance,
+                    AtomicOrdering::Relaxed,
+                    AtomicOrdering::Relaxed,
+                ) {
+                    Ok(_) => break,
+                    Err(actual) => current_max = actual,
+                }
+            }
+
+            // Track lane locality.
+            if last_thread_id == current_thread_id {
+                FSQLITE_STATEMENT_LANE_LOCAL_REUSES.fetch_add(1, AtomicOrdering::Relaxed);
+            } else {
+                FSQLITE_STATEMENT_CROSS_LANE_REUSES.fetch_add(1, AtomicOrdering::Relaxed);
+            }
+        }
+        // Update the last execution record for this statement.
+        history.insert(fingerprint_hash, (current_seq, current_thread_id));
+    });
+}
